"use strict";(self.webpackChunkdocu=self.webpackChunkdocu||[]).push([[7174],{5060:(e,n,t)=>{t.r(n),t.d(n,{assets:()=>h,contentTitle:()=>r,default:()=>c,frontMatter:()=>s,metadata:()=>i,toc:()=>d});const i=JSON.parse('{"id":"book exports/buddhism/pureland","title":"Pure Land","description":"- The Pure Land tradition probably offers the most egalitarian path to enlightenment, which partly accounts for its ubiquitous presence throughout the Mahayana Buddhist world","source":"@site/docs/book exports/buddhism/pureland.md","sourceDirName":"book exports/buddhism","slug":"/book exports/buddhism/pureland","permalink":"/docs/book exports/buddhism/pureland","draft":false,"unlisted":false,"editUrl":"https://github.com/bippyboppy/bippyboppy.github.io/tree/main/docs/docs/book exports/buddhism/pureland.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Meditations of the Pali Tradition","permalink":"/docs/book exports/buddhism/meditationsofthepalitradition"},"next":{"title":"Crypto Crackup: Sam Bankman-Fried, FTX, and SBF\'s Weird Island Empire","permalink":"/docs/book exports/cryptocrackup"}}');var a=t(4848),o=t(8453);const s={},r="Pure Land",h={},d=[];function l(e){const n={h1:"h1",header:"header",li:"li",ol:"ol",p:"p",ul:"ul",...(0,o.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.header,{children:(0,a.jsx)(n.h1,{id:"pure-land",children:"Pure Land"})}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"The Pure Land tradition probably offers the most egalitarian path to enlightenment, which partly accounts for its ubiquitous presence throughout the Mahayana Buddhist world"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsxs)(n.ol,{start:"18",children:["\n",(0,a.jsx)(n.li,{children:"If, when I attain buddhahood, sentient beings in the lands of the ten directions who sincerely and joyfully entrust themselves to me, desire to be born in my land, and think of me even ten times should not be born there, may I not attain perfect enlightenment. Excluded, however, are those who commit the five grave offenses and abuse the Right Dharma"}),"\n"]}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"For the esoteric practitioner, rapid attainment of buddhahood constituted the primary aim of practice, and this was achieved by involving the whole person in meditation. They actualized this total involvement by making sure that the practice utilized the three components of \u201cbody, speech, and mind.\u201d Sitting in a particular posture and forming a ritual hand-gesture, or mudr\u0101, brought in the body. Recitation of ritual formulas, called dh\u0101ra\u1e47\u012b or mantra, kept the voice involved. Finally, visualization of the protector deity occupied the mind. In particular, a philosophical recognition that the buddha or bodhisattva one visualized was neither the same as nor different from the practitioner led to swift awakening and buddhahood."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Before he died, the historical buddha \u015a\u0101kyamuni taught that after his departure, mentally contemplating his physical body would pacify an agitated mind. Thus, from its inception, buddha-visualization (or buddh\u0101nusm\u1e5bti in Sanskrit) has been part of the medicine cabinet of Buddhist practice"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"The Indic term buddh\u0101nusm\u1e5bti became nianfo, or \u201ccontemplation of a buddha,\u201d in Chinese, and by means of an ambiguity in this term\u2019s native meaning, nianfo came to designate the primary practice of Pure Land Buddhism."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"The word nirvana points to the state of a fire that has gone out. The Buddha often described our present world as a house on fire, and living beings as burning up with passions. To achieve the goal of Buddhist practice meant to \u201ccool down\u201d and put out these flames of suffering. However, later Buddhist thinkers such as the composers of a text called The Questions of King Milinda went further and compared living beings themselves to flames. Like a flame, we are not things or objects; we are self-perpetuating processes like fire"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Early Mahayana texts such as the Lotus S\u016btra went out of their way to explain that buddhas do not just \u201cblink out\u201d of existence, nor do they abide beyond the reach of followers who need their help. Instead, they can manifest where needed to render assistance to those still suffering. Another Mahayana text, N\u0101g\u0101rjuna\u2019s Root Stanzas on the Middle Way (Mulamadhyamaka-k\u0101rik\u0101), asserted that because of this, nirvana and samsara (the realms of rebirth and suffering) were coextensive. Thus, a buddha and an ordinary person could both be in the same place, but it would manifest to the buddha as nirvana, while for the ordinary being it remains samsara. The difference is not in the place, but in the mind"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Mahayana, therefore, traded a world in which a buddha only appeared at rare intervals for one which at all times had millions of buddhas in residence. Mahayana scriptures named them in the hundreds, and a handful gained importance and eclipsed the historical buddha in the practices of some groups: Amit\u0101bha, Ak\u1e63obhya, Vairocana, and so on"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"All beings accumulate karma, the potential energy left behind by moral deeds and habitual actions that produces results after those actions are done. This energy can take two forms"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Buddhas, by definition, are beings whose attainments have entirely purified their karma. This means that their personal qualities and the environments they inhabit will both be pure. This led to the idea of \u201cbuddha-fields\u201d or \u201cbuddha-lands,\u201d places over which buddhas reign and which, unlike our own world (called Sah\u0101 or \u201cEndurance\u201d), have no impurities, moral evil, or unfavorable rebirths. They are places where the environment is as untainted as the mind and body of the buddha that presides over it"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Vimalak\u012brti S\u016btra"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Daochuo took Tanluan\u2019s ideas and added the teaching that in the present circumstances, the \u201cpath of sages\u201d was no longer a viable option and only the \u201cPure Land path\u201d offered any hope"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"For beginners and those with little leisure for deep practice, he taught the simple method of orally reciting the name of the buddha Amit\u0101bha, while he instructed his monastic disciples and other advanced practitioners in more arduous and complex visualization exercises. Traditional biographies say he had hundreds, if not thousands, of converts. Many are said to have committed suicide in their zeal to attain immediate rebirth in the Pure Land. Shandao himself is said in many sources to have died in this manner, but few scholars accept this account. While the number of disciples who ended their own lives may be exaggerated in the sources, religious suicide was neither unheard of nor frowned upon at that time, and better-documented instances of it are not rare"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Therefore\u2026if a bodhisattva wishes to attain a pure land he should purify his mind. According to the purity of his mind is his buddha land pure."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Shandao used language that left little doubt that for him, nian meant oral repetition"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"They maintained the legitimacy of thinking that the Pure Land was a real place located to the west, a view called \u201cwestern-direction Pure Land\u201d (Ch.: xifang jingtu) in opposition to those who held that it was only the way any world appeared to a purified consciousness, a view called \u201cmind-only Pure Land\u201d (Ch.: weixin jingtu). Finally, they stood by the belief that the \u201cother-power\u201d of Amit\u0101bha brought the believer to rebirth in the Pure Land against adversaries who thought only one\u2019s own \u201cself-power\u201d availed."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"The concepts of principle (Ch.: li) and phenomenon (Ch.: shi) have been part of Chinese thought from early times. Roughly speaking, \u201cprinciple\u201d points to the abstract patterns that govern the growth, development, and movement of things, and \u201cphenomenon\u201d denotes the individual things in which those patterns manifest"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"In isolation, the search for rebirth in Sukh\u0101vat\u012b would indeed be escapist and otherworldly, \u201cmind-only\u201d would benefit no one but the person whose mind has been purified, and the search to construct a pure land in the human realm without aspirations for rebirth and mental purification would be just another form of clinging. All three forms of Pure Land have their place even within the life and practice of an individual devotee."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"He seems to have believed that the ghosts and godlings of folk religion were real enough, but he declared them irrelevant for proper Pure Land practice"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Most interestingly, Pure Land symbols have become ways of publicly identifying oneself as a Buddhist. A rosary of \u201crecitation beads\u201d (Ch.: nianzhu) around the wrist signals one\u2019s Buddhist identity as surely as a cross around the neck marks one as Christian. When encountering one another as Buddhists, people will replace \u201chello\u201d and \u201cgoodbye\u201d with the name of Amit\u0101bha"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"The earliest record of Pure Land practice in Japan dates to the year 640, when a monk named Eon, freshly returned from thirty years in China, lectured the imperial court on the Larger S\u016btra; nothing more is known of his activities. A few years later, in 658, a statue of Amit\u0101bha was installed in a temple in present-day Osaka"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"The Japanese term for this interdependence is y\u016bz\u016b, which became part of the school\u2019s name. Applied to the practice of nenbutsu, Ry\u014dnin took this to mean that no one who engages in the practice does so in isolation or without affecting others. Thus, if I recite the Buddha\u2019s name, it does not just affect me; all of the people around me are now relating to me as someone who practices nenbutsu, and so they cannot simply continue being what they were before I began"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Finally, at the age of forty-three H\u014dnen found his answer in Shandao\u2019s commentary on the Contemplation S\u016btra, which convinced him that simple oral invocation was the best and most effective practice for his troubled times. He had trained in a number of practices both contemplative and ritual, but now in 1175 he discarded all of them in favor of exclusive reliance on oral invocation of Amit\u0101bha\u2019s name"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Shinran, in contrast, made faith the centerpiece of his entire system, and in his hands it became much more than just knowing that one was bound for the Pure Land. It became instead a deep conversion experience and the very means by which rebirth became assured."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"This new way of conceiving faith grew out of Shinran\u2019s own religious crises. During his monastic career and for a time after his return to lay life he had tried to gain religious merit by means of the difficult practices of the Tendai school, and each time he felt defeated and doomed by his lack of ability. His great breakthrough came when he realized that religious exertion of any kind arose from a lack of trust in Amit\u0101bha\u2019s other-power and was an attempt to gain entry into the Pure Land via self-effort."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"His greatest departure from H\u014dnen\u2019s thought lay in his conviction that one\u2019s efforts cannot even bring about the arising of faith; Amit\u0101bha himself infuses the believer with faith as a free gift"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"If one truly believes that self-power accomplishes nothing, not even the initial welling up of faith, then any action or practice one undertakes in order to elicit Amit\u0101bha\u2019s compassion or to gain rebirth becomes immediately suspect. Thus, if one adopts the position that \u201clicensed evil,\u201d or deliberate wrongdoing assists in the process by bringing out more of the Buddha\u2019s compassion, then one is relying on self-power just as much as if one tried to observe all the precepts and achieve contemplative sam\u0101dh"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"When you look at another person, that person is simultaneously real and an image in your mind"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"When the historical buddha \u015a\u0101kyamuni passed into final nirvana, he left instructions to his monastic and lay followers regarding the direction their practice should take going forward. One practice he recommended as a way of pacifying the mind was to bring his physical form and many merits to mind, and the tradition came to call this \u201cmindfulness of the Buddha\u201d (Skt.: buddh\u0101nusm\u1e5bti). For some meditators, this technique evolved into a process of visualizing the Buddha in great detail, and later it was supplemented by philosophical reflections on the ontological status of the buddha-image that one visualized and the relationship of this buddha with the practitioner."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"A popular book that has circulated in China for many decades now is called \u201cForty-Eight Ways to Nianfo\u201d (Ch.: nianfo sishiba fa), which, as the title indicates, teaches the reader how to perform nianfo in a variety of ways depending upon his or her situation."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"In Korea, Buddhist masters formalized the teaching on the \u201cThree Gates\u201d (K.: sammun), which placed Pure Land and its practice of nianfo (K.: yeombul) alongside Zen meditation and doctrinal study as necessary components of the ideal Buddhist program"}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"In the early seventeenth century, the monk Ch\u2019ongheo Hyujong articulated this scheme, and it became a formal part of the monastic education system thereafter. In practice, clerics could choose to specialize in one or the other of these and emphasize it while minimizing the other two. However, in theory the three worked together. Chanting the Buddha\u2019s name guaranteed rebirth in the Pure Land, doctrinal study would familiarize the student with the conceptual framework within which his or her own mind was nondual with the mind and land of Amit\u0101bha, and Zen meditation would allow him or her to realize this nonduality in a direct, intuitive way."}),"\n"]}),"\n"]})]})}function c(e={}){const{wrapper:n}={...(0,o.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(l,{...e})}):l(e)}},8453:(e,n,t)=>{t.d(n,{R:()=>s,x:()=>r});var i=t(6540);const a={},o=i.createContext(a);function s(e){const n=i.useContext(o);return i.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),i.createElement(o.Provider,{value:n},e.children)}}}]);